    13→type TransflowStep struct {
    14→	Type        string     `yaml:"type"`
    15→	ID          string     `yaml:"id"`
    16→	Engine      string     `yaml:"engine"`
    17→	Recipes     []string   `yaml:"recipes"`
    18→	Model       string     `yaml:"model,omitempty"`
    19→	Prompts     []string   `yaml:"prompts,omitempty"`
    20→	MCPTools    []MCPTool  `yaml:"mcp_tools,omitempty"`
    21→	Context     []string   `yaml:"context,omitempty"`
    22→	Budgets     MCPBudgets `yaml:"budgets,omitempty"`
    23→	Parallel    bool       `yaml:"parallel,omitempty"`
    24→	MaxParallel int        `yaml:"max_parallel_execs,omitempty"`
    25→}
    26→
    27→type TransflowConfig struct {
    28→	Version      string          `yaml:"version"`
    29→	ID           string          `yaml:"id"`
    30→	TargetRepo   string          `yaml:"target_repo"`
    31→	TargetBranch string          `yaml:"target_branch"`
    32→	BaseRef      string          `yaml:"base_ref"`
    33→	Lane         string          `yaml:"lane"`
    34→	BuildTimeout string          `yaml:"build_timeout"`
    35→	Steps        []TransflowStep `yaml:"steps"`
    36→	SelfHeal     *SelfHealConfig `yaml:"self_heal"`
    37→}
    38→
    39→func LoadConfig(path string) (*TransflowConfig, error) {
    40→	b, err := ioutil.ReadFile(path)
    41→	if err != nil {
    42→		return nil, err
    43→	}
    44→	var cfg TransflowConfig
    45→	if err := yaml.Unmarshal(b, &cfg); err != nil {
    46→		return nil, err
    47→	}
    48→
    49→	// Set default self-heal config if not provided or apply defaults to existing config
    50→	if cfg.SelfHeal == nil {
    51→		cfg.SelfHeal = GetDefaultSelfHealConfig()
    52→	} else {
    53→		// Apply defaults for missing fields
    54→		if cfg.SelfHeal.MaxRetries == 0 {
    55→			cfg.SelfHeal.MaxRetries = GetDefaultSelfHealConfig().MaxRetries
    56→		}
    57→		// Cooldown defaults to empty string, so no need to set it
    58→		// For enabled field, explicit false should remain false, no default needed
    59→	}
    60→
    61→	if err := cfg.Validate(); err != nil {
    62→		return nil, err
    63→	}
    64→
    65→	return &cfg, nil
    66→}
    67→
    68→func (c *TransflowConfig) Validate() error {
    69→	if c.ID == "" {
    70→		return errors.New("id is required")
    71→	}
    72→	if c.TargetRepo == "" {
    73→		return errors.New("target_repo is required")
    74→	}
    75→	if c.BaseRef == "" {
    76→		return errors.New("base_ref is required")
    77→	}
    78→	if len(c.Steps) == 0 {
    79→		return errors.New("at least one step is required")
    80→	}
    81→
    82→	// Validate each step
    83→	for i, step := range c.Steps {
    84→		if step.ID == "" {
    85→			return fmt.Errorf("step %d must have an id", i)
    86→		}
    87→		if step.Type == "" {
    88→			return fmt.Errorf("step %d (%s) must have a type", i, step.ID)
    89→		}
    90→
    91→		// Validate MCP configuration for steps that have it
    92→		if len(step.MCPTools) > 0 || len(step.Context) > 0 {
    93→			mcpConfig := MCPConfig{
    94→				Tools:   step.MCPTools,
    95→				Context: step.Context,
    96→				Budgets: step.Budgets,
    97→				Model:   step.Model,
    98→				Prompts: step.Prompts,
    99→			}
   100→			if err := mcpConfig.Validate(); err != nil {
   101→				return fmt.Errorf("invalid MCP config for step %s: %w", step.ID, err)
   102→			}
   103→		}
   104→	}
   105→
   106→	// Validate self-heal configuration if provided
   107→	if c.SelfHeal != nil {
   108→		if err := c.SelfHeal.Validate(); err != nil {
   109→			return fmt.Errorf("invalid self_heal config: %w", err)
   110→		}
   111→	}
   112→
   113→	// Validate build timeout if provided
   114→	if c.BuildTimeout != "" {
   115→		if _, err := c.ParseBuildTimeout(); err != nil {
   116→			return fmt.Errorf("invalid build_timeout: %w", err)
   117→		}
   118→	}
   119→
   120→	return nil
   121→}
   122→
   123→func (c *TransflowConfig) ParseBuildTimeout() (time.Duration, error) {
   124→	if c.BuildTimeout == "" {
   125→		return 10 * time.Minute, nil // default
   126→	}
   127→
   128→	duration, err := time.ParseDuration(c.BuildTimeout)
   129→	if err != nil {
   130→		return 0, fmt.Errorf("invalid build timeout format: %v", err)
   131→	}
   132→
   133→	if duration < 0 {
   134→		return 0, errors.New("build timeout cannot be negative")
   135→	}
   136→
   137→	return duration, nil
   138→}
   139→
   140→func GenerateAppName(id string) string {
   141→	timestamp := time.Now().Unix()
   142→	return fmt.Sprintf("tfw-%s-%d", id, timestamp)
   143→}
   144→
   145→func GenerateBranchName(id string) string {
   146→	timestamp := time.Now().Unix()
   147→	return fmt.Sprintf("workflow/%s/%s", id, strconv.FormatInt(timestamp, 10))
   148→}
